import React, { useEffect, useState } from "react";
import styled, { keyframes } from "styled-components";

/**
 * InkWashCurtain — sumi-e (墨絵) Japanese ink-wash splash.
 *
 * Parchment / off-white page with subtle paper grain. Two large calligraphic
 * black brush sweeps draw in left-to-right via stroke-dashoffset animation,
 * edges softened with a slight gaussian blur halo so the ink "bleeds" into the
 * fibre. A small splatter dot snaps in after the strokes settle. Title fades
 * in quietly. The whole curtain fades out in a single breath.
 *
 * Total runtime ≈ 1.7s before onFinish fires (plus 400ms fade).
 */

// ===== timing =====
const STROKE_MS = 900;        // dash-offset draw duration
const STROKE_2_DELAY = 220;   // 2nd stroke begins slightly after the first
const SPLATTER_AT = 980;      // ms — splatter dot snaps in once strokes are mostly drawn
const TITLE_AT = 1080;        // ms — title reveal begins
const HOLD_MS = 1700;         // total runtime before fade trigger
const FADE_MS = 400;          // bg + ink fade
const TOTAL_MS = HOLD_MS + FADE_MS; // ~2100ms

// ===== palette =====
const PARCHMENT = "#F4EBD5";
const PARCHMENT_DEEP = "#E9DCBA";
const INK = "#0C0A08";
const INK_SOFT = "rgba(12, 10, 8, 0.78)";
const INK_MUTED = "rgba(40, 32, 22, 0.62)";

// ===== keyframes =====
// Each path uses its own stroke-dasharray length; the offset animates from the
// path's full length down to 0. We set the dasharray inline per-path and use
// CSS custom property --len for the keyframe to read.
const drawIn = keyframes`
  from { stroke-dashoffset: var(--len); }
  to   { stroke-dashoffset: 0; }
`;

const splatterPop = keyframes`
  0%   { transform: scale(0);   opacity: 0; }
  60%  { transform: scale(1.35); opacity: 1; }
  100% { transform: scale(1);   opacity: 1; }
`;

const titleReveal = keyframes`
  0%   { opacity: 0; transform: translateY(6px); letter-spacing: 0.04em; }
  100% { opacity: 1; transform: translateY(0);   letter-spacing: 0.18em; }
`;

const inkSettle = keyframes`
  0%   { opacity: 0; }
  100% { opacity: 1; }
`;

// ===== styled =====
const Wrap = styled.div`
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
  background: radial-gradient(
    ellipse 130% 90% at 50% 50%,
    ${PARCHMENT} 0%,
    ${PARCHMENT} 55%,
    ${PARCHMENT_DEEP} 100%
  );
  overflow: hidden;
  transition: opacity ${FADE_MS}ms ease;
  opacity: ${({ $fade }) => ($fade ? 0 : 1)};
`;

// Faint paper grain — a fixed SVG turbulence layer at low opacity.
const Paper = styled.svg`
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  opacity: 0.35;
  mix-blend-mode: multiply;
  pointer-events: none;
`;

const Ink = styled.svg`
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  overflow: visible;

  .brush {
    fill: none;
    stroke: ${INK};
    stroke-linecap: round;
    stroke-linejoin: round;
    animation: ${drawIn} ${STROKE_MS}ms cubic-bezier(0.22, 0.78, 0.34, 1) both;
  }

  .brush--halo {
    stroke: ${INK_MUTED};
    filter: blur(3.5px);
    opacity: 0.7;
  }

  .brush--one {
    animation-delay: 0ms;
  }

  .brush--two {
    animation-delay: ${STROKE_2_DELAY}ms;
  }

  .splatter {
    fill: ${INK_SOFT};
    transform-origin: 760px 470px;
    transform-box: fill-box;
    opacity: 0;
    animation: ${splatterPop} 260ms cubic-bezier(0.34, 1.56, 0.64, 1)
      ${SPLATTER_AT}ms both;
  }

  .splatter--micro {
    fill: ${INK_MUTED};
    transform-origin: 800px 455px;
    transform-box: fill-box;
    opacity: 0;
    animation: ${splatterPop} 240ms cubic-bezier(0.34, 1.56, 0.64, 1)
      ${SPLATTER_AT + 60}ms both;
  }
`;

const Title = styled.div`
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 18px;
  z-index: 2;
  text-align: center;
  font-family: -apple-system, "Inter", "Helvetica Neue", Arial, sans-serif;
  opacity: 0;
  animation: ${inkSettle} 600ms ease-out ${TITLE_AT}ms forwards;

  .name {
    font-size: clamp(28px, 5.4vw, 58px);
    font-weight: 900;
    letter-spacing: 0.18em;
    color: ${INK};
    text-shadow: 0 0 1px rgba(12, 10, 8, 0.15);
    animation: ${titleReveal} 700ms cubic-bezier(0.16, 1, 0.3, 1)
      ${TITLE_AT}ms both;

    span {
      color: #B22222;
      /* hanko-red dot for the period */
      margin-left: 0.02em;
    }
  }

  .tagline {
    font-family: "SF Mono", "JetBrains Mono", Menlo, Consolas, monospace;
    font-size: clamp(10px, 1.1vw, 12px);
    color: ${INK_MUTED};
    letter-spacing: 0.34em;
    text-transform: uppercase;
    animation: ${titleReveal} 700ms cubic-bezier(0.16, 1, 0.3, 1)
      ${TITLE_AT + 160}ms both;
  }
`;

// Brush stroke d-attributes — gentle hand-drawn bezier sweeps L→R.
// Designed against 1000×600 viewBox so they scale with the screen.
const STROKE_1_D =
  "M 40 282 C 180 220, 320 332, 500 270 S 820 220, 970 268";
const STROKE_2_D =
  "M 110 392 C 290 432, 460 348, 660 388 S 870 410, 950 372";

// Splatter blob path (irregular ink dot) — drawn around its own origin (760,470).
const SPLATTER_D =
  "M 760 470 m -16 -2 q 2 -10 12 -12 q 12 -2 18 6 q 8 8 4 18 q -2 10 -14 12 q -12 2 -18 -6 q -6 -8 -2 -18 z";
const SPLATTER_MICRO_D =
  "M 800 455 m -4 -1 q 1 -4 5 -4 q 5 -1 6 3 q 1 4 -3 5 q -4 1 -6 -1 q -3 -2 -2 -3 z";

// Path lengths — computed approximately from the bezier d-attributes above.
// Exact value isn't critical: the dash array is set to LEN and the offset
// animates LEN → 0, so as long as LEN ≥ actual path length the stroke draws
// from one end to the other smoothly.
const LEN_1 = 1100;
const LEN_2 = 920;

const InkWashCurtain = ({ onFinish }) => {
  const [fade, setFade] = useState(false);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const fadeT = setTimeout(() => setFade(true), HOLD_MS);
    const doneT = setTimeout(() => {
      setDone(true);
      if (onFinish) onFinish();
    }, TOTAL_MS);
    return () => {
      clearTimeout(fadeT);
      clearTimeout(doneT);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (done) return null;

  return (
    <Wrap $fade={fade}>
      {/* Subtle paper-fibre grain */}
      <Paper>
        <defs>
          <filter id="iw-grain" x="0" y="0" width="100%" height="100%">
            <feTurbulence
              type="fractalNoise"
              baseFrequency="0.85"
              numOctaves="2"
              seed="7"
            />
            <feColorMatrix
              type="matrix"
              values="0 0 0 0 0.42
                      0 0 0 0 0.32
                      0 0 0 0 0.18
                      0 0 0 0.55 0"
            />
          </filter>
        </defs>
        <rect width="100%" height="100%" filter="url(#iw-grain)" />
      </Paper>

      <Ink viewBox="0 0 1000 600" preserveAspectRatio="none">
        <defs>
          {/* Bleed filter — slight blur + displacement so brush edges feather
              into the paper rather than sit as crisp vector lines. */}
          <filter id="iw-bleed" x="-5%" y="-5%" width="110%" height="110%">
            <feTurbulence
              type="fractalNoise"
              baseFrequency="0.9"
              numOctaves="1"
              seed="3"
              result="noise"
            />
            <feDisplacementMap
              in="SourceGraphic"
              in2="noise"
              scale="2.4"
              xChannelSelector="R"
              yChannelSelector="G"
            />
          </filter>
        </defs>

        {/* Stroke 1 — long primary sweep across the top-middle.
            Halo (blurred wider stroke) sits behind the crisp ink for the
            bleed effect. */}
        <path
          className="brush brush--halo brush--one"
          d={STROKE_1_D}
          strokeWidth="78"
          style={{ "--len": LEN_1, strokeDasharray: LEN_1 }}
        />
        <path
          className="brush brush--one"
          d={STROKE_1_D}
          strokeWidth="56"
          filter="url(#iw-bleed)"
          style={{ "--len": LEN_1, strokeDasharray: LEN_1 }}
        />

        {/* Stroke 2 — shorter, lower, thinner counter-sweep */}
        <path
          className="brush brush--halo brush--two"
          d={STROKE_2_D}
          strokeWidth="54"
          style={{ "--len": LEN_2, strokeDasharray: LEN_2 }}
        />
        <path
          className="brush brush--two"
          d={STROKE_2_D}
          strokeWidth="34"
          filter="url(#iw-bleed)"
          style={{ "--len": LEN_2, strokeDasharray: LEN_2 }}
        />

        {/* Final beat: splatter dot snaps in after the strokes settle */}
        <path className="splatter" d={SPLATTER_D} filter="url(#iw-bleed)" />
        <path className="splatter--micro" d={SPLATTER_MICRO_D} />
      </Ink>

      <Title>
        <div className="name">
          DIBYAJYOTI<span>.</span>
        </div>
        <div className="tagline">Senior Software Engineer · London</div>
      </Title>
    </Wrap>
  );
};

export default InkWashCurtain;
